import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"Instalowanie oprogramowania Java na Windows","description":"Przewodnik krok po kroku o tym, jak zainstalować oprogramowanie Java na Windows.","frontmatter":{"title":"Instalowanie oprogramowania Java na Windows","description":"Przewodnik krok po kroku o tym, jak zainstalować oprogramowanie Java na Windows.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"pl_pl/1.21.8/players/installing-java/windows.md","filePath":"versions/1.21.8/translated/pl_pl/players/installing-java/windows.md","lastUpdated":1760721669000}`);var l={name:`pl_pl/1.21.8/players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalowanie oprogramowania Java na Windows <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalowanie oprogramowania Java na Windows”">​</a></h1><p>Ten przewodnik pokaże ci, jak zainstalować Javę 21 na systemie Windows.</p><p>Launcher Minecrafta zawiera własną instalację Javy, więc ta sekcja jest istotna tylko, jeśli chcesz użyć instalatora Fabric w formacie <code>.jar</code> lub jeśli chcesz użyć pliku <code>.jar</code> serwera Minecraft.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Sprawdź, czy nie masz już zainstalowanej Javy <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Sprawdź, czy nie masz już zainstalowanej Javy”">​</a></h2><p>Aby sprawdzić, czy masz już zainstalowaną Javę, musisz najpierw otworzyć wiersz poleceń.</p><p>Możesz to zrobić poprzez wciśnięcie klawiszy <kbd>Win</kbd>+<kbd>R</kbd> i wpisanie <code>cmd.exe</code> w wyświetlonym oknie.</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Okno dialogowe Uruchamiania w systemie Windows z wpisanym tekstem &quot;cmd.exe&quot; w pasku uruchamiania" loading="lazy"></p><p>Po otwarciu wiersza poleceń wpisz <code>java -version</code> i naciśnij <kbd>Enter</kbd>.</p><p>Jeśli polecenie zostanie wykonane pomyślnie, to zobaczysz coś takiego. Jeśli polecenie się nie powiodło, przejdź do następnego kroku.</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Wiersz poleceń z wpisanym poleceniem &quot;java -version&quot;" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Aby używać Minecrafta w wersji 1.21, musisz mieć zainstalowaną co najmniej Javę 21. Jeśli to polecenie wyświetla wersję mniejszą niż 21, wymagane będzie zaktualizowanie istniejącej instalacji Javy.</p></div><h2 id="2-download-the-java-installer" tabindex="-1">2. Pobierz instalator Javy 21 <a class="header-anchor" href="#2-download-the-java-installer" aria-label="Permalink to “2. Pobierz instalator Javy 21”">​</a></h2><p>Do zainstalowania Javy 21 wymagane jest pobranie instalatora ze strony Adoptium.</p><p>Pobierz wersję <code>Windows Installer (.msi)</code>:</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="Strona pobierania Adoptium z wyróżnioną wersją Windows Installer (.msi)" loading="lazy"></p><p>Jeśli masz 32-bitowy system operacyjny wybierz <code>x86</code>, natomiast jeśli masz 64-bitowy system wybierz <code>x64</code>.</p><p>Większość nowoczesnych komputerów posiada 64-bitowy system operacyjny. Jeśli nie masz pewności, spróbuj pobrać wersję 64-bitową.</p><h2 id="3-run-the-installer" tabindex="-1">3. Uruchom instalator! <a class="header-anchor" href="#3-run-the-installer" aria-label="Permalink to “3. Uruchom instalator!”">​</a></h2><p>Aby zainstalować Javę 21, postępuj zgodnie z instrukcjami w instalatorze. Gdy dotrzesz do tej strony, ustaw następujące funkcje na &quot;Cała funkcja zostanie zainstalowana na lokalnym dysku twardym&quot;:</p><ul><li><code>Set JAVA_HOME environment variable</code> - zostanie to dodane do PATH.</li><li><code>JavaSoft (Oracle) registry keys</code></li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="Instalator Javy 21 wyróżnionymi polami &quot;Set JAVA_HOME variable&quot; i &quot;JavaSoft (Oracle) registry keys&quot;" loading="lazy"></p><p>Po zrobieniu tego kliknij <code>Next</code> i kontynuuj instalację.</p><h2 id="4-verify-that-java-is-installed" tabindex="-1">4. Zweryfikuj czy Java 21 została zainstalowana <a class="header-anchor" href="#4-verify-that-java-is-installed" aria-label="Permalink to “4. Zweryfikuj czy Java 21 została zainstalowana”">​</a></h2><p>Po zakończeniu instalacji możesz zweryfikować czy Java 21 została zainstalowana, ponownie otwierając wiersz poleceń i wpisując <code>java -version</code>.</p><p>Jeśli polecenie zostanie uruchomione pomyślnie, to zobaczysz coś takiego, gdzie wyświetlana jest wersja Javy:</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Wiersz poleceń z wpisanym poleceniem &quot;java -version&quot;" loading="lazy"></p><p>Jeśli napotkasz jakiś problem, śmiało możesz poprosić o pomoc na <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discordzie Fabric</a> na kanale <code>#player-support</code>.</p>`,27)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};